const sections = document.querySelectorAll("section");
const form = document.querySelector("form");
const yearElement = document.querySelector("#year");
const nav = document.querySelector("nav");
const root = document.documentElement;
const THEME_KEY = "gdz-theme";
const THEME_PARAM = "theme";
const VALID_THEMES = new Set(["light", "dark"]);
let themeToggle = null;

const normalizeTheme = (theme) => (VALID_THEMES.has(theme) ? theme : null);

const getThemeFromUrl = () => {
  try {
    return normalizeTheme(new URLSearchParams(window.location.search).get(THEME_PARAM));
  } catch {
    return null;
  }
};

const getThemeFromWindowName = () => {
  try {
    const currentValue = String(window.name || "");
    return normalizeTheme(currentValue.replace(`${THEME_KEY}:`, ""));
  } catch {
    return null;
  }
};

const getSavedTheme = () => {
  const urlTheme = getThemeFromUrl();
  if (urlTheme) {
    return urlTheme;
  }

  try {
    const localTheme = normalizeTheme(localStorage.getItem(THEME_KEY));
    if (localTheme) {
      return localTheme;
    }
  } catch {
    // ignora bloqueios de armazenamento local
  }

  try {
    const sessionTheme = normalizeTheme(sessionStorage.getItem(THEME_KEY));
    if (sessionTheme) {
      return sessionTheme;
    }
  } catch {
    // ignora bloqueios de armazenamento de sessão
  }

  return getThemeFromWindowName();
};

const syncThemeInUrl = (theme) => {
  try {
    const url = new URL(window.location.href);
    url.searchParams.set(THEME_PARAM, theme);
    window.history.replaceState({}, "", url.toString());
  } catch {
    // ignora limitações em alguns modos locais
  }
};

const updateThemeLinks = (theme) => {
  document.querySelectorAll('a[href]').forEach((link) => {
    const href = link.getAttribute("href");

    if (!href || href.startsWith("#") || /^(mailto:|tel:|javascript:)/i.test(href)) {
      return;
    }

    try {
      const url = new URL(href, window.location.href);
      const isInternalHtml = url.pathname.toLowerCase().endsWith(".html");
      const isSameSite = url.protocol === "file:" || url.origin === window.location.origin;

      if (!isInternalHtml || !isSameSite) {
        return;
      }

      url.searchParams.set(THEME_PARAM, theme);
      link.setAttribute("href", url.toString());
    } catch {
      // ignora links inválidos
    }
  });
};

const saveTheme = (theme) => {
  const normalizedTheme = normalizeTheme(theme);

  if (!normalizedTheme) {
    return;
  }

  try {
    localStorage.setItem(THEME_KEY, normalizedTheme);
  } catch {
    // ignora bloqueios de armazenamento local
  }

  try {
    sessionStorage.setItem(THEME_KEY, normalizedTheme);
  } catch {
    // ignora bloqueios de armazenamento de sessão
  }

  try {
    window.name = `${THEME_KEY}:${normalizedTheme}`;
  } catch {
    // ignora limitações do navegador
  }

  syncThemeInUrl(normalizedTheme);
  updateThemeLinks(normalizedTheme);
};

const updateThemeToggle = (theme) => {
  if (!themeToggle) {
    return;
  }

  const isDark = theme === "dark";
  themeToggle.setAttribute("aria-pressed", String(isDark));
  themeToggle.setAttribute(
    "title",
    isDark ? "Mudar para tema claro" : "Mudar para tema escuro"
  );
  themeToggle.innerHTML = `
    <span class="theme-icon" aria-hidden="true">${isDark ? "☀️" : "🌙"}</span>
    <span class="theme-label">${isDark ? "Tema claro" : "Tema escuro"}</span>
  `;
};

const applyTheme = (theme, persist = false) => {
  const normalizedTheme = normalizeTheme(theme) || "light";

  root.setAttribute("data-theme", normalizedTheme);
  root.style.colorScheme = normalizedTheme;
  updateThemeToggle(normalizedTheme);
  updateThemeLinks(normalizedTheme);

  if (persist) {
    saveTheme(normalizedTheme);
  }
};

const savedTheme = getSavedTheme();
const preferredTheme = savedTheme || "dark";

applyTheme(preferredTheme);

if (savedTheme) {
  saveTheme(preferredTheme);
}

const revealOnScroll = () => {
  sections.forEach((section) => {
    const rect = section.getBoundingClientRect();
    if (rect.top < window.innerHeight - 100) {
      section.classList.add("visible");
    }
  });
};

window.addEventListener("scroll", revealOnScroll);
window.addEventListener("load", revealOnScroll);

if (form) {
  const submitButton = form.querySelector('button[type="submit"]');
  const successRedirectField = form.querySelector('input[name="_next"]');
  const consentCheckbox = form.querySelector('input[name="privacy_consent"]');
  const formStatus = document.querySelector("#form-status");

  const setFormStatus = (message, type = "") => {
    if (!formStatus) {
      return;
    }

    formStatus.textContent = message;
    formStatus.className = `form-feedback${type ? ` ${type}` : ""}`;
  };

  const syncSubmitState = () => {
    if (!submitButton) {
      return;
    }

    const hasConsent = !consentCheckbox || consentCheckbox.checked;
    submitButton.disabled = !hasConsent;
    submitButton.textContent = hasConsent ? "Enviar mensagem" : "Aceite a política para enviar";
  };

  if (successRedirectField) {
    try {
      const successUrl = new URL(window.location.href);
      successUrl.searchParams.set("enviado", "1");
      successRedirectField.value = successUrl.toString();
    } catch {
      // mantém o valor padrão se a URL não puder ser montada
    }
  }

  if (consentCheckbox) {
    syncSubmitState();
    consentCheckbox.addEventListener("change", () => {
      syncSubmitState();
    });
  }

  form.addEventListener("submit", async (event) => {
    const action = (form.getAttribute("action") || "").trim();
    const hasRealAction = Boolean(action) && action !== "#";

    if (consentCheckbox && !consentCheckbox.checked) {
      event.preventDefault();
      setFormStatus(
        "Para enviar o formulário, aceite primeiro os termos da Política de Privacidade e Proteção de Dados.",
        "error"
      );
      consentCheckbox.focus();
      syncSubmitState();
      return;
    }

    if (!hasRealAction) {
      event.preventDefault();
      alert("Obrigado pelo contato! Sua mensagem foi recebida. Entraremos em contato em breve.");
      form.reset();
      return;
    }

    event.preventDefault();

    if (submitButton) {
      submitButton.disabled = true;
      submitButton.textContent = "Enviando...";
    }

    setFormStatus("Enviando sua mensagem...", "");

    try {
      const ajaxEndpoint = action.includes("formsubmit.co/")
        ? action.replace("https://formsubmit.co/", "https://formsubmit.co/ajax/")
        : action;

      const response = await fetch(ajaxEndpoint, {
        method: "POST",
        body: new FormData(form),
        headers: {
          Accept: "application/json"
        }
      });

      const responseText = await response.text();
      let result = null;

      try {
        result = responseText ? JSON.parse(responseText) : null;
      } catch {
        // ignora respostas não JSON
      }

      if (!response.ok) {
        throw new Error(result?.message || `Falha no envio: ${response.status}`);
      }

      if (String(result?.success ?? "").toLowerCase() === "false") {
        throw new Error(result?.message || "O serviço de envio recusou a mensagem.");
      }

      form.reset();
      syncSubmitState();
      setFormStatus("Mensagem enviada com sucesso! Em breve entraremos em contato.", "success");
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : "";
      const requiresActivation = /activat(e|ion)|needs activation/i.test(errorMessage);

      setFormStatus(
        requiresActivation
          ? "O formulário precisa ser reativado no FormSubmit. Verifique o e-mail gdzconsultoria@outlook.com e clique em \"Activate Form\"."
          : "Não foi possível enviar agora. Tente novamente em instantes ou use o WhatsApp ao lado.",
        "error"
      );
    } finally {
      if (submitButton) {
        submitButton.disabled = false;
        submitButton.textContent = "Enviar mensagem";
      }

      syncSubmitState();
    }
  });
}

if (yearElement) {
  yearElement.textContent = new Date().getFullYear();
}

try {
  const params = new URLSearchParams(window.location.search);
  if (params.get("enviado") === "1") {
    alert("Mensagem enviada com sucesso! Em breve entraremos em contato.");
    params.delete("enviado");
    const nextQuery = params.toString();
    const nextUrl = `${window.location.pathname}${nextQuery ? `?${nextQuery}` : ""}${window.location.hash}`;
    window.history.replaceState({}, "", nextUrl);
  }
} catch {
  // ignora limitações de URL no navegador
}

if (nav) {
  nav.setAttribute("id", "main-nav");

  const ensureNavLink = (href, label) => {
    if (nav.querySelector(`a[href*="${href}"]`)) {
      return;
    }

    const link = document.createElement("a");
    link.href = href;
    link.textContent = label;

    const contactLink = Array.from(nav.querySelectorAll("a")).find((navLink) =>
      (navLink.getAttribute("href") || "").toLowerCase().includes("contato.html")
    );

    if (contactLink) {
      nav.insertBefore(link, contactLink);
    } else {
      nav.appendChild(link);
    }
  };

  ensureNavLink("blog.html", "Blog");
  ensureNavLink("parcerias.html", "Parcerias");

  const currentPage = (window.location.pathname.split("/").pop() || "index.html").toLowerCase();
  nav.querySelectorAll("a").forEach((link) => {
    const rawHref = (link.getAttribute("href") || "").split("?")[0].split("#")[0].toLowerCase();
    const targetPage = rawHref.split("/").pop();

    if (targetPage && targetPage === currentPage) {
      link.classList.add("active");
      link.setAttribute("aria-current", "page");
    } else {
      link.removeAttribute("aria-current");
    }
  });

  themeToggle = document.createElement("button");
  themeToggle.className = "theme-toggle";
  themeToggle.setAttribute("type", "button");
  themeToggle.setAttribute("aria-label", "Alternar tema do site");
  nav.parentNode.insertBefore(themeToggle, nav);
  updateThemeToggle(root.getAttribute("data-theme") || preferredTheme);

  themeToggle.addEventListener("click", () => {
    const currentTheme = root.getAttribute("data-theme") === "dark" ? "dark" : "light";
    const nextTheme = currentTheme === "dark" ? "light" : "dark";
    applyTheme(nextTheme, true);
  });

  const toggle = document.createElement("button");
  toggle.className = "nav-toggle";
  toggle.setAttribute("type", "button");
  toggle.setAttribute("aria-expanded", "false");
  toggle.setAttribute("aria-controls", "main-nav");
  toggle.innerHTML =
    '<span class="bar bar1"></span><span class="bar bar2"></span><span class="bar bar3"></span><span class="sr-only">Menu</span>';
  nav.parentNode.insertBefore(toggle, nav);

  updateThemeLinks(root.getAttribute("data-theme") || preferredTheme);

  toggle.addEventListener("click", () => {
    const isOpen = nav.classList.toggle("open");
    toggle.classList.toggle("open", isOpen);
    toggle.setAttribute("aria-expanded", String(isOpen));
  });

  nav.querySelectorAll("a").forEach((link) => {
    link.addEventListener("click", () => {
      if (nav.classList.contains("open")) {
        nav.classList.remove("open");
        toggle.classList.remove("open");
        toggle.setAttribute("aria-expanded", "false");
      }
    });
  });
}

const counters = document.querySelectorAll("[data-counter]");

const animateCounter = (counter) => {
  if (counter.dataset.animated === "true") {
    return;
  }

  counter.dataset.animated = "true";
  const target = Number(counter.dataset.counter || "0");

  if (!Number.isFinite(target)) {
    counter.textContent = counter.dataset.counter || "0";
    return;
  }

  const duration = 1200;
  const startTime = performance.now();

  const step = (timestamp) => {
    const progress = Math.min((timestamp - startTime) / duration, 1);
    const eased = 1 - Math.pow(1 - progress, 3);
    const value = Math.round(target * eased);
    counter.textContent = String(value);

    if (progress < 1) {
      window.requestAnimationFrame(step);
    }
  };

  window.requestAnimationFrame(step);
};

if (counters.length) {
  if ("IntersectionObserver" in window) {
    const counterObserver = new IntersectionObserver(
      (entries, observer) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            animateCounter(entry.target);
            observer.unobserve(entry.target);
          }
        });
      },
      { threshold: 0.35 }
    );

    counters.forEach((counter) => counterObserver.observe(counter));
  } else {
    counters.forEach((counter) => animateCounter(counter));
  }
}

